+inline int32_t computeLog2(int32_t val, std::string const& name = "") {
+  int32_t n = val;
+  int32_t out = 0;
+  while (n >>= 1) {
+    ++out;
+  }
+  TORCH_CHECK((1 << out) == val, "Expected %s to be a power of 2, got %d", name.c_str(), val);
+  return out;
+}
