+        auto const numBytesSmemStoreC = usesSmemForGmemC
+                                            ? extraGmemCMultiplier * epilogueTileM * epilogueTileN *
+                                                  tg::dtypeGetNumBits(dtypeSmemC) / 8 /* bits */
+                                            : 0;
