+      {
+        // Does the MMA require block scales in TMEM for B?
+        bool const useBlockScalingB = tg::dtypeIsBlockFmt(dtypeMmaB);
+        // Are the block scales constant?
+        bool const useConstSfB = useBlockScalingB && !tg::dtypeIsBlockFmt(dtypeB);
