+  }
+
+ public:
+  // The MMA kind.
+  tg::MmaKind mMmaKind;
+  // Helper for SMEM allocation.
+  MemAllocatorHelper mSmemAllocatorHelper;
+  // Helper for TMEM allocation.
+  MemAllocatorHelper mTmemAllocatorHelper;
+};
